 * For more details on building Java & JVM projects, please refer to https://docs.gradle.org/9.3.1/userguide/building_java_projects.html in the Gradle documentation.
 */

plugins {
    // Apply the application plugin to add support for building a CLI application in Java.
    application
}

repositories {
    // Use Maven Central for resolving dependencies.
    mavenCentral()
}

dependencies {
    // Use JUnit Jupiter for testing.
    testImplementation(libs.junit.jupiter)

    testRuntimeOnly("org.junit.platform:junit-platform-launcher")

    // This dependency is used by the application.
    implementation(libs.guava)

    // JSoup - parser HTML/SGML do plików Reuters .sgm
    implementation("org.jsoup:jsoup:1.18.3")

    // Source: https://mvnrepository.com/artifact/com.github.rholder/snowball-stemmer
    implementation("com.github.rholder:snowball-stemmer:1.3.0.581.1")
}

// Apply a specific Java toolchain to ease working on different environments.
java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(25)
    }
}

application {
    // Define the main class for the application.
    mainClass = "org.bir.knn.App"
}

tasks.named<Test>("test") {
    // Use JUnit Platform for unit tests.
    useJUnitPlatform()
}

tasks.register<JavaExec>("runKnnAutomation") {
    group = "application"
    description = "Uruchamia zautomatyzowane eksperymenty KNN"
    classpath = sourceSets["main"].runtimeClasspath
    mainClass = "org.bir.knn.KnnAutomatedTestRunner"

    val rawArgs = project.findProperty("appArgs")?.toString()?.trim().orEmpty()
    if (rawArgs.isNotBlank()) {
        args(rawArgs.split("\\s+".toRegex()))
    }
}

